  ('bookkeeper-moex-01416', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '被繼承人之配偶依民法第一千零三十條之一規定主張配偶剩餘財產差額分配請求權且自遺產總額中扣除者， 若納稅義務人未於稽徵機關核發稅款繳清證明書或免稅證明書之日起幾年內，給付該請求權金額之財產予 被繼承人之配偶者，稽徵機關應就未給付部分追繳應納稅賦？', '["一年內", "二年內", "三年內", "五年內"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
