  ('bookkeeper-moex-01420', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國記帳士法之規定，下列敘述何者正確？', '["記帳士登錄後，可以申請不加入記帳士公會，自行執業", "記帳士公會得拒絕具有會員資格者加入", "記帳士因懈怠或疏忽，致委任人或其利害關係人受有損害時，應負賠償責任", "記帳士受委任後，非有正當事由，不得終止其契約。如須終止契約，應於30日前通知委任人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
